#!/usr/bin/env bash
set -euo pipefail

echo "=== Simulador de Premiação - Instalador ADS Software ==="

# Detectar gerenciador de pacotes
if command -v apt >/dev/null 2>&1; then
  PKG="apt"
  export DEBIAN_FRONTEND=noninteractive
  apt update -qq
  apt install -y -qq apache2 unzip >/dev/null
elif command -v dnf >/dev/null 2>&1; then
  PKG="dnf"
  dnf install -y -q httpd unzip >/dev/null
  systemctl enable --now httpd
elif command -v yum >/dev/null 2>&1; then
  PKG="yum"
  yum install -y -q httpd unzip >/dev/null
  systemctl enable --now httpd
else
  echo "ERRO: gerenciador de pacotes não detectado (apt/dnf/yum)."
  exit 1
fi

# Detectar pasta web e usuário do servidor
if [ -d /var/www/html ]; then
  WEBROOT="/var/www/html/premiacao"
elif [ -d /var/www ]; then
  WEBROOT="/var/www/premiacao"
else
  WEBROOT="/srv/premiacao"
  mkdir -p "$WEBROOT"
fi

if id www-data >/dev/null 2>&1; then WEBUSER="www-data:www-data"
elif id apache  >/dev/null 2>&1; then WEBUSER="apache:apache"
elif id nginx   >/dev/null 2>&1; then WEBUSER="nginx:nginx"
else WEBUSER="root:root"; fi

mkdir -p "$WEBROOT"
TMPZIP=$(mktemp --suffix=.zip)
echo "==> Decodificando arquivos..."

base64 -d > "$TMPZIP" << 'BASE64_PAYLOAD'

BASE64_PAYLOAD

unzip -o -q "$TMPZIP" -d "$WEBROOT"
rm -f "$TMPZIP"
chown -R "$WEBUSER" "$WEBROOT"
chmod -R 755 "$WEBROOT"

# Garantir que o Apache está rodando
if systemctl list-units --type=service --all | grep -q apache2; then
  systemctl enable --now apache2 >/dev/null 2>&1 || true
elif systemctl list-units --type=service --all | grep -q httpd; then
  systemctl enable --now httpd >/dev/null 2>&1 || true
fi

# Liberar firewall, se existir
if command -v ufw >/dev/null 2>&1; then ufw allow 80/tcp >/dev/null 2>&1 || true; fi
if command -v firewall-cmd >/dev/null 2>&1; then
  firewall-cmd --permanent --add-service=http >/dev/null 2>&1 || true
  firewall-cmd --reload >/dev/null 2>&1 || true
fi

# Pegar IP público
IP=$(curl -s --max-time 5 https://api.ipify.org || hostname -I | awk '{print $1}')

echo ""
echo "============================================================"
echo "  INSTALADO COM SUCESSO"
echo "============================================================"
echo "  Pasta:   $WEBROOT"
echo ""
echo "  URLs:"
echo "    http://$IP/premiacao/consultor-premiacao.html"
echo "    http://$IP/premiacao/supervisor-premiacao.html"
echo "    http://$IP/premiacao/testes.html"
echo "============================================================"
